// In dylib crates all pub functions are exported symbols, so rustc reports
// improper_ctypes_definitions for any that use non-FFI types like Vec<T>.
// The actual FFI boundary is the _cm companion generated by #[tomii_export],
// which only uses CmTypes. Suppress the lint for the original Rust-to-Rust functions.
#![allow(improper_ctypes_definitions)]

use tomii_macro::tomii_export;

// 2048 sin accumulations ≈ 30 µs per call on a modern x86 core.
// Keeps scheduling overhead < 15 % of wall time at N=256 so the S-scaling
// comparison measures dispatch efficiency rather than resolution overhead.
// Must match TRANSFORM_ITERS in pipeline-bench/taskflow/src/main.cpp.
const TRANSFORM_ITERS: usize = 8192;

#[inline(never)]
fn heavy_transform(x: f64) -> f64 {
    let mut acc = 0.0f64;
    for i in 1..=TRANSFORM_ITERS {
        acc += (x * i as f64).sin();
    }
    acc / TRANSFORM_ITERS as f64
}

/// Initialise a zero-filled output buffer of length `n`.
///
/// Used as a shared `$ref` initialisation object that `pl_emit` writes into.
#[tomii_export]
pub fn pl_init_output(n: usize) -> Vec<f64> {
    vec![0.0f64; n]
}

/// Stage 1 — ingest: produce item `idx` for a stream of `n` items.
///
/// Returns `(idx + 1) / n` as a normalised f64 in `(0, 1]`.
#[tomii_export]
pub fn pl_ingest(idx: usize, n: usize) -> f64 {
    (idx as f64 + 1.0) / n as f64
}

/// Stage 2 — transform: heavy pointwise kernel (~30 µs at TRANSFORM_ITERS=2048).
///
/// Returns `f64` directly; stored as `CmTypes::F64` (no heap allocation).
/// The variadic fan-in in `pl_aggregate` uses the numeric extraction path.
#[tomii_export]
pub fn pl_transform(x: f64) -> f64 {
    heavy_transform(x)
}

/// Stage 3 — aggregate: fan-in barrier that collects all N transform outputs.
///
/// Each element of `chunks` is the `f64` produced by one `pl_transform` instance.
/// Returns the arithmetic mean across all N items.
#[tomii_export(variadic)]
pub fn pl_aggregate(chunks: Vec<f64>) -> f64 {
    let n = chunks.len();
    if n == 0 {
        return 0.0;
    }
    chunks.iter().sum::<f64>() / n as f64
}

/// Stage 4 — emit: write the computed mean into the shared output buffer.
///
/// `stream_id` is unused at runtime (the slot index is tracked by the
/// runtime) but is kept for debugging and future per-stream accounting.
/// Returns `mean` so downstream nodes can observe it if needed.
#[tomii_export]
pub fn pl_emit(mean: f64, stream_id: usize) -> f64 {
    let _ = stream_id;
    mean
}

/// Stage 4 (verification variant) — emit mean and append to a result file.
///
/// Identical signature to pl_emit; additionally writes the mean to the path in
/// PIPELINE_BENCH_RESULT (if set) so verify.py can capture per-stream values.
#[tomii_export]
pub fn pl_emit_to_file(mean: f64, stream_id: usize) -> f64 {
    let _ = stream_id;
    if let Ok(path) = std::env::var("PIPELINE_BENCH_RESULT") {
        use std::io::Write;
        if let Ok(mut f) = std::fs::OpenOptions::new()
            .create(true).append(true).open(&path)
        {
            let _ = writeln!(f, "{:.10}", mean);
        }
    }
    mean
}

/// Verification kernel: checks that all emit results equal the expected
/// pipeline mean within a tolerance of 1e-6.
///
/// NOTE: this function is not wired into the benchmark graph automatically.
/// The verify.py script reads result files and recomputes expected values.
#[tomii_export(variadic)]
pub fn pl_verify_output(n: usize, results: Vec<f64>) -> bool {
    let expected: f64 = (0..n)
        .map(|i| {
            let x = (i as f64 + 1.0) / n as f64;
            heavy_transform(x)
        })
        .sum::<f64>()
        / n as f64;

    let all_ok = results
        .iter()
        .all(|&v| (v - expected).abs() < 1e-6);

    if !all_ok {
        let bad: Vec<(usize, f64)> = results
            .iter()
            .enumerate()
            .filter(|(_, &v)| (v - expected).abs() >= 1e-9)
            .map(|(i, &v)| (i, v))
            .collect();
        eprintln!(
            "[pl_verify_output] FAIL: expected {:.10}, {} bad slots: {:?}",
            expected,
            bad.len(),
            &bad[..bad.len().min(5)]
        );
    }

    all_ok
}
